const cita = $input.first().json;
const trigger = $('Trigger - Execute Workflow').first().json;

if (cita.id) {
  const fecha = cita.scheduled_at
    ? new Date(cita.scheduled_at).toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })
    : 'por confirmar';
  return [{ json: {
    success: true,
    response: `Tu cita ha sido registrada para el ${fecha}. Estado: pendiente de confirmación. Te avisaremos cuando sea confirmada.`
  }}];
}

// Errores de dominio: { code, message, details } con HTTP 400
// (slot_unavailable, no_professional_available, professional_unavailable).
// El message ya viene redactado para el paciente -> mostrarlo tal cual.
if (cita.code && cita.message) {
  return [{ json: { success: false, response: cita.message } }];
}

let errorMsg = '';

if (cita.detail) {
  errorMsg = cita.detail;
} else if (cita.non_field_errors) {
  errorMsg = [].concat(cita.non_field_errors).join(' ');
} else if (typeof cita === 'object' && cita !== null) {
  const parts = Object.entries(cita).map(([field, msg]) => {
    const text = [].concat(msg).join(', ');
    return text;
  });
  errorMsg = parts.join(' ');
}

const fallback = 'No hemos podido crear tu cita en este momento. Por favor, llámanos para agendar tu visita.';

return [{ json: {
  success: false,
  response: errorMsg || fallback
}}];

const result = $input.first().json;
if (result.status === 'cancelled' || result.id) {
  return [{ json: { success: true, response: 'Tu cita ha sido cancelada correctamente. Si necesitas agendar otra, no dudes en escribirnos.' }}];
} else {
  return [{ json: { success: false, response: 'No hemos encontrado una cita activa para cancelar. ¿Puedes indicarnos más detalles?' }}];
}

const raw = $input.first().json;
const citas = raw.results || (Array.isArray(raw) ? raw : []);

if (!citas.length) {
  return [{ json: { success: true, response: 'No tienes citas pendientes en este momento.' }}];
}

const lista = citas.map((c, i) => {
  const fecha = new Date(c.scheduled_at).toLocaleString('es-ES', {timeZone: 'Europe/Madrid'});
  const estado = c.status === 'confirmed' ? 'Confirmada' : 'Pendiente';
  return `${i+1}. ${fecha} - ${estado}`;
}).join('\n');

return [{ json: { success: true, response: `Tus próximas citas:\n${lista}` }}];

const action = $('Trigger - Execute Workflow').first().json.action || 'desconocida';
return [{ json: {
  success: false,
  response: 'No he entendido tu solicitud. Puedo ayudarte a agendar, consultar o cancelar citas.'
}}];

const patient = $('F - Crear Paciente').first().json;

if (patient.id) {
  return [{ json: {
    success: true,
    response: `¡Perfecto, ${patient.first_name}! Ya estás registrado/a. ¿En qué puedo ayudarte? Puedo informarte sobre nuestros servicios, ayudarte a agendar una cita...`
  }}];
} else {
  return [{ json: {
    success: false,
    response: 'Ha habido un problema al registrarte. Por favor, inténtalo de nuevo.'
  }}];
}

const norm = $('Normalizar Inputs').first().json;

return [{ json: {
  clinic_id: norm.clinic_id,
  first_name: norm.first_name || '',
  last_name: norm.last_name || '',
  phone: norm.phone,
  email: norm.email || ''
}}];

const trigger = $input.first().json;
let p = {};
try { p = typeof trigger.params === 'string' ? JSON.parse(trigger.params) : (trigger.params || {}); } catch(e) {}

const django_auth_header = trigger.django_auth_header || ''
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1)
const tomorrowFormated = tomorrow.toISOString()

const confirm = p.confirm === true || String(p.confirm || '').toLowerCase() === 'true';

return [{ json: {
  action: trigger.action || '',
  phone: trigger.phone || '',
  clinic_id: trigger.clinic_id || '',
  django_auth_header: django_auth_header,
  service: p.service || '',
  service_id: p.service_id ? parseInt(p.service_id) : null,
  professional_id: p.professional_id ? parseInt(p.professional_id) : null,
  professional_name: p.professional_name || p.professional || '',
  preferred_date: p.preferred_date || '',
  preferred_time: p.preferred_time || '09:00',
  appointment_id: p.appointment_id || '',
  first_name: p.first_name || '',
  last_name: p.last_name || '',
  email: p.email || '',
  date: p.date || tomorrowFormated || '',
  duration: p.duration || 30,
  confirm: confirm,
  response: p.response || ''
}}];

const raw = $input.first().json;
const items = raw.results || (Array.isArray(raw) ? raw : []);
if (!items.length) return [{ json: { output: 'No hay servicios disponibles.', success: true } }];
const lines = items.map(s => {
  const price = s.price ? ` - ${s.price}€` : '';
  const dur = s.duration ? ` (${s.duration} min)` : '';
  return `• ${s.name}${price}${dur}`;
});
return [{ json: { output: 'Servicios disponibles:\n' + lines.join('\n'), success: true } }];

const raw = $input.first().json;
const items = raw.results || (Array.isArray(raw) ? raw : []);
if (!items.length) return [{ json: { output: 'No hay profesionales disponibles.', success: true } }];
const lines = items.map(p => {
  const info = p.user_info || {};
  const name = info.full_name || (info.first_name && info.last_name ? info.first_name + ' ' + info.last_name : 'Sin nombre');
  const tipo = p.professional_type_display || p.professional_type || '';
  const services = (p.services_detail || []).map(s => s.name + ' (' + s.duration_minutes + 'min, ' + s.price + '€)').join(', ');
  const svcStr = services ? ' → ' + services : '';
  return '• [ID:' + p.id + '] ' + name + (tipo ? ' (' + tipo + ')' : '') + svcStr;
});
return [{ json: { output: 'Profesionales:\n' + lines.join('\n'), success: true } }];

const norm = $('Normalizar Inputs').first().json;

// Validaciones de negocio: devolver respuesta amigable (NO throw) para no romper el subworkflow
if (!norm.professional_id) {
  return [{ json: { valid: false, success: false, response: 'Para consultar horarios disponibles necesito saber con qué profesional. Usa action=list_professionals para ver los disponibles.' } }];
}

let date = norm.date || norm.preferred_date || '';
if (date) {
  const parsed = new Date(date);
  if (!isNaN(parsed.getTime())) {
    date = date.replace(/T.*$/, '').substring(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
      date = parsed.toISOString().split('T')[0];
    }
  } else {
    return [{ json: { valid: false, success: false, response: 'El formato de fecha no es válido: ' + date + '. Usa el formato yyyy-MM-dd (ejemplo: 2026-05-08).' } }];
  }
} else {
  const now = new Date();
  const madridNow = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
  madridNow.setDate(madridNow.getDate() + 1);
  const y = madridNow.getFullYear();
  const m = String(madridNow.getMonth() + 1).padStart(2, '0');
  const d = String(madridNow.getDate()).padStart(2, '0');
  date = y + '-' + m + '-' + d;
}

const needs_service_lookup = !norm.service_id && !!norm.service;
if (!norm.service_id && !norm.service) {
  return [{ json: { valid: false, success: false, response: 'Para consultar horarios necesito el servicio. Indica el nombre del servicio (ej: "empaste", "revisión") o usa action=list_services para ver los disponibles.' } }];
}

return [{ json: {
  valid: true,
  professional_id: norm.professional_id,
  service_id: norm.service_id || null,
  service_name: norm.service || '',
  date_slots: date,
  duration: norm.duration || 30,
  django_auth_header: norm.django_auth_header,
  clinic_id: norm.clinic_id,
  needs_service_lookup: needs_service_lookup
}}];

const validated = $('I - Validar Entrada Slots').first().json;
const raw = $input.first().json;
const items = raw.results || (Array.isArray(raw) ? raw : []);

const serviceName = (validated.service_name || '').toLowerCase().trim();

let match = items.find(s => s.name.toLowerCase() === serviceName);
if (!match) {
  match = items.find(s =>
    s.name.toLowerCase().includes(serviceName) ||
    serviceName.includes(s.name.toLowerCase())
  );
}

if (!match) {
  const available = items.map(s => s.name).join(', ');
  // No romper el subworkflow: devolver respuesta amigable y cortar via IF posterior
  return [{ json: { found: false, success: false, response: 'No encontré el servicio "' + validated.service_name + '". Servicios disponibles: ' + available + '. Usa action=list_services para ver todos.' } }];
}

return [{ json: {
  found: true,
  professional_id: validated.professional_id,
  service_id: match.id,
  service_name: match.name,
  date_slots: validated.date_slots,
  duration: validated.duration,
  django_auth_header: validated.django_auth_header,
  clinic_id: validated.clinic_id,
  needs_service_lookup: false
}}];

const raw = $input.first().json;
if (raw.works_this_day === false) {
  const prof = raw.professional_name || 'El profesional';
  const fecha = raw.date || $('Normalizar Inputs').first().json.date || '';
  const msg = prof + ' no trabaja el ' + fecha + '. Por favor, elige otra fecha.';
  return [{ json: { output: msg, success: true, works_this_day: false } }];
}
const slots = raw.available_slots || raw.slots || (Array.isArray(raw) ? raw : []);
if (!slots.length) return [{ json: { output: 'No hay horarios disponibles para esa fecha.', success: true } }];
const limited = slots.slice(0, 16);
const lines = limited.map(s => {
  const raw_time = typeof s === 'string' ? s : (s.time || s.start_time || s.slot || '');
  const timeStr = raw_time.includes('T') ? raw_time.split('T')[1].substring(0, 5) : raw_time.substring(0, 5);
  return '• ' + timeStr;
});
const extra = slots.length > 16 ? '\n... y ' + (slots.length - 16) + ' más.' : '';
const fecha = raw.date || $('Normalizar Inputs').first().json.date || '';
const prof = raw.professional_name ? ' con ' + raw.professional_name : '';
let scheduleInfo = '';
if (raw.schedule && raw.schedule.start_time && raw.schedule.end_time) {
  scheduleInfo = ' (horario ' + raw.schedule.start_time.substring(0, 5) + '–' + raw.schedule.end_time.substring(0, 5) + ')';
}
const header = fecha ? 'Horarios disponibles' + prof + scheduleInfo + ' para el ' + fecha + ':' : 'Horarios disponibles' + prof + scheduleInfo + ':';
return [{ json: { output: header + '\n' + lines.join('\n') + extra, success: true } }];

const norm = $('Normalizar Inputs').first().json;

if (!norm.professional_id) {
  throw new Error('Para consultar la agenda del profesional necesito el ID del profesional. Usa action=list_professionals para ver los disponibles.');
}

return [{ json: {
  professional_id: norm.professional_id,
  django_auth_header: norm.django_auth_header,
  clinic_id: norm.clinic_id
}}];

const raw = $input.first().json;
const items = raw.results || (Array.isArray(raw) ? raw : []);
if (!items.length) return [{ json: { output: 'No hay citas pendientes para este profesional.', success: true } }];
const lines = items.map(a => {
  const fecha = a.scheduled_at ? a.scheduled_at.substring(0, 16).replace('T', ' ') : 'Sin fecha';
  const paciente = a.patient_name || a.patient || 'Paciente';
  const servicio = a.service_name || a.service || '';
  return `• ${fecha} - ${paciente}${servicio ? ' (' + servicio + ')' : ''} [${a.status || ''}]`;
});
return [{ json: { output: 'Agenda:\n' + lines.join('\n'), success: true } }];

const norm = $('Normalizar Inputs').first().json;
const requestedId = String(norm.appointment_id || '').trim();
const confirmed = norm.confirm === true;
const raw = $input.first().json;
const appointments = raw.results || (Array.isArray(raw) ? raw : []);

function formatCita(a, index) {
  const dt = new Date(a.scheduled_at);
  const fecha = dt.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Madrid' });
  const hora = dt.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
  const servicio = a.service_name || a.service || 'Consulta';
  const profesional = a.professional_name || a.professional || '';
  const prefix = index !== undefined ? (index + 1) + '. ' : '';
  const profStr = profesional ? ('\n   ' + profesional) : '';
  return prefix + '*' + servicio + '*\n   ' + fecha + ' a las ' + hora + profStr;
}

if (appointments.length === 0) {
  return [{ json: {
    proceed: false,
    response: 'No tienes citas activas proximas para cancelar. Si necesitas agendar una nueva cita, con mucho gusto te ayudo.'
  }}];
}

// Identificar la cita objetivo: por appointment_id indicado, o la unica activa
let selected = null;
if (requestedId) {
  selected = appointments.find(function(a) { return String(a.id) === requestedId; }) || null;
}
if (!selected && appointments.length === 1) {
  selected = appointments[0];
}

if (selected) {
  // Paso 2: solo cancelar si el usuario ha confirmado explicitamente
  if (confirmed) {
    return [{ json: {
      proceed: true,
      appointment_id: selected.id,
      response: 'De acuerdo, procedo a cancelar tu cita.'
    }}];
  }
  // Paso 1: pedir confirmacion, sin cancelar todavia
  return [{ json: {
    proceed: false,
    appointment_id: selected.id,
    response: 'Vas a cancelar esta cita:\n\n' + formatCita(selected) + '\n\nConfirmas la cancelacion? Responde SI para confirmar o NO para mantenerla.',
    appointments: [{ numero: 1, id: selected.id }]
  }}];
}

// Varias citas y ninguna seleccionada: pedir que elija
const lista = appointments.map(function(a, i) { return formatCita(a, i); }).join('\n\n');
const appointmentsList = appointments.map(function(a, i) { return { numero: i + 1, id: a.id }; });
return [{ json: {
  proceed: false,
  response: 'Tienes varias citas activas proximas:\n\n' + lista + '\n\nCual quieres cancelar? Responde con el numero correspondiente.',
  appointments: appointmentsList
}}];

const raw = $input.first().json;
const norm = $('Normalizar Inputs').first().json;

let preferredDate = norm.preferred_date;
if (!preferredDate) {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  preferredDate = tomorrow.toISOString().split('T')[0];
}

let slots = [];
if (Array.isArray(raw)) {
  slots = raw;
} else if (raw.slots && Array.isArray(raw.slots)) {
  slots = raw.slots;
} else if (raw.results && Array.isArray(raw.results)) {
  slots = raw.results;
} else if (raw.available_slots && Array.isArray(raw.available_slots)) {
  slots = raw.available_slots;
}

const fecha = new Date(preferredDate).toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

if (!slots.length) {
  return [{ json: {
    success: true,
    response: `Lo siento, no hay horarios disponibles para ${fecha}. ¿Quieres que revisemos otro día?`
  }}];
}

const listaHorarios = slots.map(slot => {
  if (typeof slot === 'string') return `• ${slot}`;
  if (slot.time) return `• ${slot.time}`;
  if (slot.start_time) return `• ${slot.start_time}`;
  if (slot.hour) return `• ${slot.hour}`;
  return `• ${JSON.stringify(slot)}`;
}).join('\n');

return [{ json: {
  success: true,
  response: `Estos son los horarios disponibles para el ${fecha}:\n\n${listaHorarios}\n\n¿Cuál te viene mejor?`
}}];

const norm = $('Normalizar Inputs').first().json;
const patientsRaw = $('B - Buscar Paciente').first().json;
const patients = patientsRaw.results || (Array.isArray(patientsRaw) ? patientsRaw : []);

if (!patients.length) {
  throw new Error('Paciente no encontrado para phone: ' + norm.phone);
}

const patient = patients[0];

// Buscar servicio por nombre con match parcial
let service_id = norm.service_id || null;
let serviceDuration = 30;

if (!service_id) {
  const serviciosRaw = $('B - Buscar Servicio').first().json;
  const servicios = serviciosRaw.results || (Array.isArray(serviciosRaw) ? serviciosRaw : []);
  const query = (norm.service || '').toLowerCase().trim();

  let match = null;
  if (query) {
    match = servicios.find(s => s.name.toLowerCase() === query);
    if (!match) match = servicios.find(s => s.name.toLowerCase().includes(query));
    if (!match) match = servicios.find(s => query.includes(s.name.toLowerCase()));
  }
  if (!match && servicios.length === 1) match = servicios[0];

  if (match) {
    service_id = match.id;
    if (match.duration_minutes) serviceDuration = match.duration_minutes;
  }
}

if (!service_id) {
  throw new Error('Servicio no encontrado: ' + (norm.service || 'no especificado') + '. Usa action=list_services para ver los disponibles.');
}

// Resolver professional_id
let professional_id = norm.professional_id ? parseInt(norm.professional_id) : null;

if (!professional_id) {
  const profRaw = $('B - Buscar Profesional').first().json;
  const profs = profRaw.results || (Array.isArray(profRaw) ? profRaw : []);

  if (profs.length === 1) {
    professional_id = profs[0].id;
  } else if (profs.length > 1) {
    const searchName = (norm.professional_name || '').toLowerCase().trim();
    if (searchName) {
      const match = profs.find(p => {
        const info = p.user_info || {};
        const fullName = (info.full_name || (info.first_name + ' ' + info.last_name) || '').toLowerCase();
        return fullName.includes(searchName) || searchName.includes(fullName.split(' ')[0]);
      });
      professional_id = match ? match.id : null;
    }
  }
}

if (!professional_id) {
  throw new Error('Profesional no encontrado: ' + (norm.professional_name || 'no especificado') + '. Usa action=list_professionals para ver los disponibles.');
}

const date = norm.preferred_date || '';
const time = norm.preferred_time || '09:00';

if (!date) {
  throw new Error('Se requiere preferred_date para crear la cita.');
}

function getMadridOffsetHours(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const madridHour = parseInt(d.toLocaleString('en-US', {
    timeZone: 'Europe/Madrid',
    hour: 'numeric',
    hour12: false
  }));
  let diff = madridHour - 12;
  if (diff > 12) diff -= 24;
  if (diff < -12) diff += 24;
  return diff;
}

const offsetHours = getMadridOffsetHours(date);
const sign = offsetHours >= 0 ? '+' : '-';
const offsetStr = sign + String(Math.abs(offsetHours)).padStart(2, '0') + ':00';

const scheduledAt = date + 'T' + time + ':00' + offsetStr;

const [h, m] = time.split(':').map(Number);
const utcStart = new Date(Date.UTC(
  parseInt(date.substring(0, 4)),
  parseInt(date.substring(5, 7)) - 1,
  parseInt(date.substring(8, 10)),
  h - offsetHours,
  m,
  0
));
utcStart.setMinutes(utcStart.getMinutes() + serviceDuration);
const endAt = utcStart.toISOString();

return [{ json: {
  patient_id: patient.id,
  clinic_id: patient.clinic,
  service_id: service_id,
  professional_id: professional_id,
  scheduled_at: scheduledAt,
  end_at: endAt,
  phone: norm.phone
}}];

